// Generated by GitHub Copilot
import useCart from '../context/useCart';

/**
 * ProductCard displays a single product with an accessible "Add to cart" button.
 * @param {{ product: object }} props
 */
export default function ProductCard({ product }) {
  const { dispatch, cart, isFavorite, toggleFavorite, showToast } = useCart();

  const isInCart = cart.some((item) => item.id === product.id);
  const favorite = isFavorite(product.id);

  const handleAdd = () => {
    dispatch({ type: 'ADD_ITEM', payload: product });
    showToast(`Agregaste "${product.name}" al carrito`, 'success');
  };

  return (
    <article
      className="bg-white rounded-2xl shadow hover:shadow-md transition-shadow overflow-hidden flex flex-col"
      aria-label={`Producto: ${product.name}`}
    >
      <img
        src={product.image}
        alt={product.name}
        className="w-full h-48 object-cover"
        loading="lazy"
      />
      <div className="p-4 flex flex-col flex-1 gap-2">
        <div className="flex items-start justify-between gap-2">
          <span className="text-xs font-medium text-indigo-500 uppercase tracking-wide">
            {product.category}
          </span>
          <button
            type="button"
            onClick={() => toggleFavorite(product)}
            className={`rounded-full px-2 py-1 text-xs font-semibold transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600 ${
              favorite
                ? 'bg-rose-100 text-rose-700 hover:bg-rose-200'
                : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
            aria-pressed={favorite}
            aria-label={`${favorite ? 'Quitar de favoritos' : 'Agregar a favoritos'}: ${product.name}`}
          >
            {favorite ? '❤ Favorito' : '♡ Favorito'}
          </button>
        </div>
        <h2 className="text-gray-800 font-semibold text-base leading-tight">{product.name}</h2>
        <p className="text-gray-500 text-sm flex-1">{product.description}</p>
        <div className="flex items-center justify-between mt-2">
          <span className="text-lg font-bold text-gray-900">${product.price.toFixed(2)}</span>
          <button
            type="button"
            onClick={handleAdd}
            className="bg-indigo-600 hover:bg-indigo-700 active:scale-95 text-white text-sm font-medium px-4 py-2 rounded-lg transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
            aria-label={`${isInCart ? 'Agregar otro' : 'Agregar al carrito'}: ${product.name}`}
          >
            {isInCart ? '+ Agregar otro' : 'Agregar al carrito'}
          </button>
        </div>
      </div>
    </article>
  );
}
